sql:
SELECT COUNT(*) AS failed_jobs_count
FROM job_execution_history
WHERE status = 'failed';

SELECT device_name
FROM storage_devices
WHERE device_type = 'hard drive';

SELECT user_name, email, role, department
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM benchmarking_jobs
);

SELECT template_name
FROM job_templates
WHERE category = 'write';

SELECT throughput
FROM job_results
WHERE job_id = 1;

SELECT COUNT(job_id) AS job_count
FROM device_job_history
WHERE device_id = 0;

SELECT job_id, pattern, description
FROM benchmarking_jobs
WHERE pattern = 'read';

